console.log("正在编辑链接，linkId = "+linkId);layui.use(["form","layer"],function(){let form=layui.form;let layer=layui.layer;let link;let options=[];if(linkId){form.verify({name:function(b,a){let nameRex=/^[\w\W\s\u4e00-\u9fcc]{2,20}$/;if(!nameRex.test(b)){return"链接名只能为2-20个字符"}}});$.ajax({url:"/link_type",method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200&&a.data){$.each(a.data,function(b,c){$("#type").append(new Option(c.name,c.name));options.push(c)});$.ajax({url:"/link/"+linkId,method:"GET",dataType:"json",success:function(b){if(b.request==="success"&&b.status===200&&b.data){link=b.data[0];$("#type option").each(function(c,d){if($(d).text()===link.type){$(d).attr("selected","selected")}});form.val("form-link",{id:link.id,url:link.url,name:link.name});form.render()}else{layer.msg(b.message+", 错误码: "+b.status,{icon:2})}},error:function(b){if(b){layer.msg(b)}else{layer.msg("请求错误，请检查网络",{icon:2})}}})}else{layer.msg(a.message+", 错误码: "+a.status,{icon:2})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});form.on("submit(form-link-submit)",function(a){let link=a.field;layer.confirm("确认提交？",{btn:["确认","取消"]},function(b){$.ajax({url:"/link/"+linkId,data:{url:link.url,name:link.name,type:link.type},method:"PUT",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false})}else{layer.msg("参数错误",{icon:2})}});